Dani javanski program pretvorite v diagram poteka. 
public class programcek { 
   public static void main(String[] args) { 
      int j=2020, i=30; 
      while (j > i) { 
         System.out.println("j="+j+"   i="+i); 
         j = j / i; 
         if (i % 2 == 0) 
            i = i – 5; 
         else  
            i = i – 10; 
      }; 
      System.out.println("j="+j+"   i="+i); 
   } 
}

