Kaj izpiše program? 
public class Igraca { 
   String ime; 
   public static int x=100; 
   Igraca(){ 
      ime="medvedek"; 
      x=0; 
   } 
   Igraca(String a){ 
      ime=a; 
      x++; 
   } 
   public void izpis(){ 
      System.out.println(ime + " " + x); 
   } 
   public static void main(String args[]) { 
      Igraca[] a=new Igraca[4]; 
      int i; 
      for (i=0;i<4; i++) 
         if (i%2==0)  
            a[i]=new Igraca("žoga");  
         else  
            a[i]=new Igraca(); 
      for (i=0;i<4; i++) 
         a[i].izpis();       
   } 
}
